5	  it("returns empty array when given empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
