30	    // L-shape: (0,0),(1,0),(0,1). Dead cell (1,1) has 3 live neighbors -> alive.
31	    const cells: [number, number][] = [[0, 0], [1, 0], [0, 1]];
32	    const result = nextGeneration(cells);
33	    const resultSet = new Set(result.map((c) => c.join(",")));
34	    expect(resultSet.has("1,1")).toBe(true);
35	  });
